#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>
#include <omp.h>

#include "backprop.h"

#ifndef WIDTH
#define WIDTH 16
#endif

#ifndef HEIGHT
#define HEIGHT 16
#endif

extern void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2);
extern void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err);
extern void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err);
extern void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw);

extern int setup(int argc, char **argv);
extern float **alloc_2d_dbl(int m, int n);
extern float squash(float x);

unsigned int num_threads = 0;
unsigned int num_blocks = 0;

__attribute__((weak))
double gettime() {
  struct timeval t;
  gettimeofday(&t, NULL);
  return t.tv_sec + t.tv_usec * 1e-6;
}

__attribute__((weak))
int main(int argc, char **argv) {
  return setup(argc, argv);
}

void bpnn_train_cuda(BPNN *net, float *eo, float *eh) {
  int in, hid, out;
  float out_err, hid_err;
  int j, k, by;

  (void)eo;
  (void)eh;

  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;

  num_blocks = (unsigned int)(in / HEIGHT);

  printf("Performing GPU computation\n");

  net->input_units[0] = 1.0f;

#pragma omp parallel for private(j, by, k) schedule(static)
  for (j = 1; j <= hid; j++) {
    float sum = 0.0f;
    for (by = 0; by < (int)num_blocks; by++) {
      int base = by * HEIGHT;
      for (k = 1; k <= HEIGHT; k++) {
        int idx = base + k;
        sum += net->input_weights[idx][j] * net->input_units[idx];
      }
    }
    sum += net->input_weights[0][j];
    net->hidden_units[j] = 1.0f / (1.0f + expf(-sum));
  }

  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);
  bpnn_adjust_weights(net->hidden_delta, hid, net->input_units, in, net->input_weights, net->input_prev_weights);
}

__attribute__((weak))
void bpnn_train_kernel(BPNN *net, float *eo, float *eh) {
  bpnn_train_cuda(net, eo, eh);
}
